                                                <td className="p-4">
                                                    <div className="text-white">{student.college}</div>
                                                    <div className="text-sm text-slate-400">{student.dept}</div>
                                                </td>
                                                <td className="p-4 flex space-x-2">
                                                    {Object.entries(student.profiles).map(([key, url]) => (
