                                                            'bg-orange-500/20 text-orange-300'
                                                        }`}>
                                                        {student.status}
                                                    </span>
                                                </td>
                                                <td className="p-4 space-x-2">
                                                    {student.status !== 'Verified' && (
                                                        <>
                                                            <button onClick={() => handleVerify(student._id, 'Verified')} className="text-green-400 hover:text-green-300">Verify</button>
                                                            <button onClick={() => handleVerify(student._id, 'Rejected')} className="text-red-400 hover:text-red-300">Reject</button>
                                                        </>
                                                    )}
                                                    <button onClick={() => handleDelete(student._id)} className="text-slate-500 hover:text-red-500 transition-colors ml-2" title="Delete Student">
                                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                                        </svg>
                                                    </button>
                                                </td>
                                            </>
                                        )}
                                    </motion.tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
            {/* Student Details Modal */}
            <StudentDetailsModal student={selectedStudent} onClose={() => setSelectedStudent(null)} />
        </div>
    );
};

