                                    >
                                        {filter !== 'Total' && getProfileIcon(filter.toLowerCase())}
                                        {filter}
                                    </button>
                                ))}
                            </div>

                            {/* Leaderboard Table */}
                            <div className="overflow-x-auto rounded-xl bg-slate-900/50 border border-slate-700/50">
                                {loadingLeaderboard ? (
                                    <div className="p-8 text-center text-slate-400">Loading Leaderboard...</div>
