                                                    <td className="p-4 font-mono text-slate-300">{s.regNo}</td>
                                                    <td className="p-4 font-semibold text-white">{s.name}</td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                )}
                            </div>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
};

